import React from "react";
import Home from "../Pages/Home";
import Contract from "../Components/Contract";
import Login from "../Pages/Login";
import Payment from "../Pages/Payment";
import Book from "../Pages/Book";
import Reservations from "../Pages/Reservations";
import { Routes, Route, useLocation } from "react-router-dom";
import Contact from "../Pages/Contact";
import Services from "../Pages/Services";
import About from "../Pages/About";
import { AnimatePresence } from "framer-motion";

function AnimatedRoutes(props) {
  //attention here!! (I think the location const was used by the AnimatePresence)
  const location = useLocation();
  return (
    <div>
      <AnimatePresence location={location.pathname}>
        <Routes>
          <Route path="*" element={<Home isLogged={props.isLogged} />} />
          <Route path="/book/*" element={<Book isLogged={props.isLogged} />} />
          <Route
            path="/login/*"
            element={<Login isLogged={props.isLogged} />}
          />
          <Route path="/reservations" element={<Reservations />} />
          <Route
            path="/contract/*"
            element={
              <Contract isLogged={props.isLogged} itsOkay={props.itsOkay} />
            }
          />
          <Route
            path="/contact"
            element={<Contact isLogged={props.isLogged} />}
          />
          <Route path="/services" element={<Services />} />
          <Route path="/about" element={<About />} />
          <Route
            path="/payment/*"
            element={<Payment isLogged={props.isLogged} />}
          />
          <Route path="/reservations" element={<Reservations />} />
        </Routes>
      </AnimatePresence>
    </div>
  );
}

export default AnimatedRoutes;
