import React, { Component } from "react";
import { Link } from "react-router-dom";
import Contract from "../Components/Contract";
import axios from "axios";
import { motion } from "framer-motion";
import emailjs from "emailjs-com";
import '../input-style.css';

const pdfFile = require("../short photography contract.pdf");
const api = axios.create({ baseURL: "http://localhost:3001" });

class Book extends Component {
  state = {
    data: {
      timeInicio: "",
      timeFim: "",
      place: "",
      imageNumber: "50",
      resolution: "medium",
      type: "personal",
      price: "0",
    },
    itsOkay: true,
  };

  handleForm = (e) => {
    const dataToSend = { ...this.state.data };
    dataToSend[e.target.id] = e.target.value;
    this.setState({ data: dataToSend });
  };

  openContract() {
    if (this.props.isLogged === false) {
      alert("User must be logged");
      return "User must be logged";
    }
    var blur = document.getElementById("blur");
    blur.classList.toggle("active");
    var popup = document.getElementById("popup");
    popup.classList.toggle("active");
  }

  setData() {
    const data = {
      timeInicio: this.state.data.timeInicio,
      timeFim: this.state.data.timeFim,
      place: this.state.data.place,
      imageNumber: this.state.data.imageNumber,
      resolution: this.state.data.resolution,
      type: this.state.data.type,
      price: this.state.data.price,
    };
    return data;
  }

  sendData(data) {
    if (this.props.isLogged === true) {
      const resp = api.post("/setDetails", data).then(
        (resp) => {
          // this.setState({ itsOkay: true });
          // window.open("http://localhost:3000/payment");
          console.log("Data Saved sucessfully");
          return true;
        },
        (err) => {
          // this.setState({ itsOkay: false });
          console.log("Error while saving", err.text);
          return true;
        }
      );
    } else {
      alert("You need to login first");
      window.open("http://localhost:3000/login", "_self");
    }
    return false;
  }

  submitForm(e) {
    document.getElementById("message").value = JSON.stringify(this.state.data);
    const data = this.setData();
    if (this.sendData(data)) {
      e.preventDefault();
      emailjs
        .sendForm(
          "service_uaxwktv",
          "template_zhmszrn",
          e.target,
          "QXKIOsJR522n30JF-"
        )
        .then(
          (result) => {
            console.log("Code: ", result, "Email Sent");
          },
          (error) => {
            console.log("Error while Sending email", error.text);
          }
        );
    } else {
      alert("Error while submiting form");
    }
  }

  openPdf() {
    console.log("opened");
    window.open(pdfFile, "_self");
  }

  getPrice() {
    return "67678";
  }

  render() {
    return (
      <motion.div
        initial={{ opacity: 0, width: 0 }}
        animate={{ opacity: 1, width: "100%", type: "none" }}
        transition={{type: "spring", stiffness: 75}}
        exit={{
          opacity: 0,
          width: window.innerWidth,
          transition: { duration: 0.1 },
        }}
      >
        <script src="input-script.js"></script>
        <div className="cont" id="blur">
          <div className="content">
            <h1 className="text-black md:text-3xl text-2xl flex justify-center md:m-3 m-8 align-center">
              Booking page
            </h1>
            <form
              id="submitData"
              onSubmit={(e) => this.submitForm(e)}
              className="mx-5 mb-10 mt-2 "
            >
              {/* for emailjs */}
              <input
                type="text"
                name="subject"
                onChange={(e) => this.handleForm(e)}
                value="CDK"
                hidden
              ></input>
              <input
                type="text"
                id="message"
                name="message"
                onChange={(e) => this.handleForm(e)}
                value={() => this.getMessage()}
                hidden
              ></input>

              <div className="fields">
                <div className="input-field">
                  <label>Adress</label>
                  <div className="grid md:mx-5">
                    <input
                      type=""
                      id="place"
                      placeholder="Enter the adress"
                      value={this.state.data.place}
                      style={{ width: "350px" }}
                      required
                      onChange={(e) => this.handleForm(e)}
                    />
                  </div>
                </div>
                <div className="input-field">
                  <label>Enter start and finish time</label>
                  <div className="md:grid md:grid-cols-2">
                    <div className="grid">
                      <input
                        type="time"
                        id="timeInicio"
                        placeholder="Enter show up time"
                        style={{ width: "165px", margin: "10px" }}
                        required
                        onChange={(e) => this.handleForm(e)}
                      />
                    </div>
                    <div className="grid">
                      <input
                        type="time"
                        id="timeFim"
                        placeholder="Enter finish time"
                        style={{ width: "165px", margin: "10px" }}
                        required
                        onChange={(e) => this.handleForm(e)}
                      />
                    </div>
                  </div>
                </div>

                <div className="input-field">
                  <div className="md:grid md:grid-cols-2 ">
                    <div className="grid">
                      <label className="flex justify-center align-center">
                        Number of Photos
                      </label>
                      <select
                        id="imageNumber"
                        style={{ width: "165px", margin: "10px" }}
                        value={this.state.data.imageNumber}
                        required
                        onChange={(e) => this.handleForm(e)}
                      >
                        <option>50</option>
                        <option>150</option>
                        <option>350</option>
                        <option>500</option>
                      </select>
                    </div>
                    <div className="grid">
                      <label className="flex justify-center align-center">
                        Resolution
                      </label>
                      <select
                        id="resolution"
                        style={{ width: "165px", margin: "10px" }}
                        value={this.state.data.resolution}
                        required
                        onChange={(e) => this.handleForm(e)}
                      >
                        <option>Medium</option>
                        <option>High</option>
                        <option disabled>Ultra High</option>
                      </select>
                    </div>
                  </div>
                </div>

                <div className="input-field">
                  <label>Type</label>
                  <select
                    style={{ width: "175px" }}
                    id="type"
                    value={this.state.data.type}
                    required
                    onChange={(e) => this.handleForm(e)}
                  >
                    <option>Personal</option>
                    <option>Business</option>
                    <option>Other</option>
                  </select>
                </div>

                <div className="input-field">
                  <label>Price</label>
                  <input
                    type="text"
                    id="price"
                    placeholder="$"
                    min="10"
                    max="500"
                    value={() => this.getPrice()}
                    style={{ width: "175px", fontSize: "15px" }}
                    disabled
                    onChange={(e) => this.handleForm(e)}
                  />
                </div>

                <div className="buttons, flex justify-center align-center items-center">
                  <Link
                    to="/"
                    style={{ textStyle: "none" }}
                    className="backBtnLink"
                  >
                    <button className="backBtn">back</button>
                  </Link>
                  <button
                    onClick={() => this.openContract()}
                    className="backBtn"
                  >
                    Book
                  </button>
                </div>
              </div>
            </form>
            <h1
              onClick={() => window.open(pdfFile, "_self")}
              className="flex justify-left align-left underline duration-1000 flex-wrap text-1xl hover:text-pink-800 hover:cursor-pointer text-black"
            >
              View Contract
            </h1>
          </div>
        </div>
        <Contract />
      </motion.div>
    );
  }
}

export default Book;
